INSERT INTO schedule_plans (id, species, name, emoji, intro_title, intro_description, tips_title, tips_body, min_age_days, max_age_days) VALUES
  ('dog_newborn', 'dog', 'Newborn (0–8 weeks)', '🐣', 'Newborn (0–8 weeks)', 'This stage is entirely mom-led. Puppies are blind, deaf, and fully dependent. Your role is monitoring health, weight, and warmth — not scheduling. They nurse every 2 hours around the clock.', '🐣 Key Notes', 'If mom is present, let her do the work — your job is observation. Call your vet immediately if any pup is losing weight, crying constantly, rejected by mom, or feels cold to the touch. The socialization window (weeks 3–12) is the most critical period for a dog''s entire life — exposure now shapes temperament forever.', 0, 56),
  ('dog_young_puppy', 'dog', 'Young Puppy (8–12 weeks)', '🍼', 'Young Puppy (8–12 weeks)', 'The classic "new puppy" stage. Awake windows are only 1–1.5 hrs. Expect overnight potty trips, 3 meals/day, and lots of crate naps.', '🍼 Key Notes', 'Potty outside within 5–10 min of every meal, nap, and play session. Training sessions = 5 min max. Overnight trips should be boring on purpose — lights low, no talking. She''ll drop the overnight trip around 4–5 months.', 56, 84),
  ('dog_3_4_months', 'dog', '3–4 Months', '🌱', '3–4 Months', 'Awake windows stretch to ~2 hrs. Drop to 2 naps per day. Overnight potty trips become less frequent and may disappear entirely by month 4.', '🌱 Key Notes', 'Start leash manners now — short, positive walks. Increase training complexity: down, stay, leave it, loose leash. Socialization window is closing — prioritize new people, dogs, and environments. Potty intervals can stretch to every 2–3 hrs during the day.', 84, 120),
  ('dog_4_6_months', 'dog', '4–6 Months', '🐕', '4–6 Months', 'Most pups sleep through the night now. Awake windows hit 3 hrs. You can stay at 3 meals/day or begin transitioning to 2 — check with your vet.', '🐕 Key Notes', 'Overnight potty trips should be fully gone by now — celebrate! Adolescence begins around 5–6 months; expect some stubbornness and testing of boundaries. Stay consistent. Start working on recall, stay, and leave it in more distracting environments. Keep potty intervals to every 3 hrs max during the day.', 120, 180),
  ('dog_6_12_months', 'dog', '6–12 Months', '🦮', '6–12 Months', 'Two meals/day. More physical exercise needed. Adolescence peaks around 6–9 months — training consistency matters more than ever. Crate becomes optional for settled dogs.', '🦮 Key Notes', 'Adolescence is the hardest stretch — your pup may seem to "forget" training. Stay consistent and patient. Focus on real-world skills: greeting strangers politely, ignoring distractions on walks, staying calm at doors. Physical exercise + mental enrichment = a calmer dog. Potty intervals can now stretch to 4 hrs.', 180, 365),
  ('dog_adult', 'dog', 'Adult (1–7 years)', '🐶', 'Adult (1–7 years)', 'Two meals/day, 2–3 walks/day, no forced nap schedule. Bladder holds 4–6 hours comfortably. Training shifts to maintenance and fun activities.', '🐶 Key Notes', 'Exercise needs vary hugely by breed — a Border Collie needs 2 hrs/day, a Basset Hound is happy with 30 min. Mental enrichment (sniff walks, training, puzzle toys) is just as tiring as physical exercise. Annual vet checkups are key at this stage. Keep training skills fresh with occasional refreshers.', 365, 2555),
  ('dog_senior', 'dog', 'Senior (7+ years)', '🦳', 'Senior (7+ years)', 'Large breeds hit senior status around 6–7; small breeds around 10+. Shorter, gentler exercise. May need a midday potty trip back. Watch for joint stiffness, appetite changes, and cognitive signs.', '🦳 Key Notes', 'Bi-annual vet visits are recommended for seniors (every 6 months). Watch for: increased drinking/urinating, appetite loss, confusion at night, difficulty rising, or incontinence. Joint supplements (fish oil, glucosamine) may help — ask your vet. Keep their brain active with easy nose work and gentle training. Love them loudly — they''ve earned it. 🐾', 2555, NULL),
  ('cat_newborn', 'cat', 'Newborn (0–4 weeks)', '🐣', 'Newborn (0–4 weeks)', 'Entirely mom-dependent. Kittens are blind, deaf, and cannot regulate their own body temperature or eliminate without stimulation. Your role is monitoring — not scheduling.', '🐣 Key Notes', 'Fading Kitten Syndrome can strike fast — call your vet immediately if any kitten is cold, unresponsive, crying constantly, or not gaining weight. The socialization window is 2–9 weeks: the most important period in a cat''s life for human bonding. Gentle handling now = a friendlier cat forever.', 0, 28),
  ('cat_kitten', 'cat', 'Young Kitten (4–12 weeks)', '🍼', 'Young Kitten (4–12 weeks)', 'Weaning completes around 8 weeks. Kittens eat 4× a day, sleep in bursts, and enter their peak socialization window. Play is essential — it''s how they learn to be cats.', '🍼 Key Notes', 'Litter box: one box per cat plus one extra. Kittens figure it out quickly — place them in the box after every meal. Use unscented clumping litter. Never punish litter box misses — just clean and redirect. First vet visit should happen at 8 weeks for vaccines, deworming, and a health check.', 28, 84),
  ('cat_junior', 'cat', 'Junior (3–6 months)', '🌱', 'Junior (3–6 months)', 'Dropping to 3 meals/day. Growing fast — needs calorie-dense food. Zoomies are real. Spay/neuter window begins around 4–5 months. Personality is crystallizing.', '🌱 Key Notes', 'Spay/neuter is typically recommended around 4–5 months — before first heat in females. This dramatically reduces health risks and behavioral issues. Teething happens 3–6 months; redirect biting to toys, never hands. Start nail trims now — weekly touch of paws builds tolerance.', 84, 180),
  ('cat_adolescent', 'cat', 'Adolescent (6–18 months)', '🐈', 'Adolescent (6–18 months)', 'The "teenager" phase. High energy, boundary-testing, and peak nighttime activity. Two meals/day. Fully switched to adult food by 12 months. May become more territorial.', '🐈 Key Notes', 'The bedtime play session is the single most effective tool for reducing nighttime disruption — don''t skip it. If introducing a second cat, do it slowly: separate rooms, scent swapping first, then visual contact. Litter box hygiene becomes more important as territory instincts sharpen — scoop daily.', 180, 365),
  ('cat_adult', 'cat', 'Adult (1–7 years)', '🐱', 'Adult (1–7 years)', 'Two meals/day, consistent routine, and daily interactive play. This is the longest phase — the goal is enrichment, bonding, and prevention. Annual vet checkups are essential.', '🐱 Key Notes', 'Cats are obligate carnivores — quality of food matters enormously. Wet food is strongly preferred over dry for hydration and kidney health. Annual vet checkups catch issues early; dental disease is the most common and preventable problem. Keep the litter box scrupulously clean — cats will find creative alternatives if they dislike it.', 365, 2555),
  ('cat_mature', 'cat', 'Mature (7–11 years)', '🦳', 'Mature (7–11 years)', 'Often called the "middle-aged" cat. May start slowing down but is still very healthy. Bi-annual vet visits begin. Watch for weight changes, thirst, and litter box habits — these are the early warning signals.', '🦳 Key Notes', 'Bi-annual vet visits are the standard of care from here on. Blood panel once a year helps catch hyperthyroidism, kidney disease, and diabetes early — all common in cats this age. Weight loss despite good appetite is a red flag. Lower litter box sides if jumping becomes difficult. Keep routines as consistent as possible; mature cats are creatures of deep habit.', 2555, 4015),
  ('cat_senior', 'cat', 'Senior (11+ years)', '🌙', 'Senior / Elder (11+ years)', 'Cats at this age can live well into their late teens. Shorter, gentler everything — play, walks, grooming. Comfort, warmth, and familiarity matter most. Some cognitive decline is normal.', '🌙 Key Notes', 'Bi-annual vet visits with blood work are essential. Arthritis is very common and very treatable — watch for reluctance to jump, stiffness after rest, or missing the litter box. Provide ramps or steps to favorite spots. Keep food, water, and litter on the same floor. Nighttime yowling, disorientation, or staring into space may indicate feline cognitive dysfunction — talk to your vet. These years are precious. 🐾', 4015, NULL);
